#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
#define _i128 __int128
using namespace std;
const int N = 2e5+5;
struct query{LL l,r,id,o;}q[N];
LL n,B,a[N],m,cnt;
LL c1[N],c2[N],L,R,nowAns,ans[N];
LL read(){
    LL su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
bool cmp(query q1,query q2){
    if(q1.l/B!=q2.l/B)return q1.l/B<q2.l/B;
    return q1.r<q2.r;
}
void Add1(int x){nowAns+=c2[x],c1[x]++;return;}
void Del1(int x){nowAns-=c2[x],c1[x]--;return;}
void Add2(int x){nowAns+=c1[x],c2[x]++;return;}
void Del2(int x){nowAns-=c1[x],c2[x]--;return;}
int main(){
    n=read(),B=sqrt(n);
    for(int i=1;i<=n;i++)a[i]=read();
    m=read();
    for(int i=1;i<=m;i++){
        int l1=read(),r1=read();
        int l2=read(),r2=read();
        q[++cnt]={r1,r2,i,1};
        q[++cnt]={r1,l2-1,i,-1};
        q[++cnt]={l1-1,r2,i,-1};
        q[++cnt]={l1-1,l2-1,i,1};
    }
    sort(q+1,q+cnt+1,cmp);
    for(int i=1;i<=cnt;i++){
        int ql=q[i].l,qr=q[i].r;
        while(L<ql)Add1(a[++L]);
        while(R<qr)Add2(a[++R]);
        while(L>ql)Del1(a[L--]);
        while(R>qr)Del2(a[R--]);
        ans[q[i].id]+=q[i].o*nowAns;
    }
    for(int i=1;i<=m;i++)cout<<ans[i]<<"\n";
    return 0;
}
